        if not vhosts:
            print("No vhosts found or unable to retrieve vhost list.")
            return issues

        # Get all permissions
        response = self._make_request("GET", "permissions")
        if response.status_code != 200:
            print("Unable to retrieve permissions for audit.")
            return issues

        all_permissions = response.json()

        # Check for overly broad permissions
        for perm in all_permissions:
            user = perm.get("user", "")
            vhost = perm.get("vhost", "")
            configure = perm.get("configure", "")
            write = perm.get("write", "")
            read = perm.get("read", "")

            # Flag wildcard permissions (except for admin users)
            for perm_type, perm_value in [("configure", configure), ("write", write), ("read", read)]:
                if perm_value == ".*":
                    issue = (
                        f"WARN: User '{user}' has wildcard {perm_type} permission "
                        f"on vhost '{vhost}'"
                    )
                    issues.append(issue)
                    print(f"  {issue}")

            # Flag guest user with any permissions
            if user == "guest":
                issue = f"CRITICAL: Guest user has permissions on vhost '{vhost}'"
                issues.append(issue)
                print(f"  {issue}")

        # Check for users with access to multiple tenant vhosts
        user_vhosts = {}
        for perm in all_permissions:
            user = perm.get("user", "")
            vhost = perm.get("vhost", "")
            if vhost.startswith("tenant_"):
                if user not in user_vhosts:
                    user_vhosts[user] = []
                user_vhosts[user].append(vhost)

        for user, vhost_list in user_vhosts.items():
            if len(vhost_list) > 1:
                issue = (
                    f"WARN: User '{user}' has access to multiple tenant vhosts: "
                    f"{', '.join(vhost_list)}"
                )
                issues.append(issue)
                print(f"  {issue}")

        if not issues:
            print("  No isolation issues found.")

        print("=" * 60 + "\n")
        return issues

