def main():
    """Main function demonstrating multi-tenant RabbitMQ setup."""

    import os

    # Configuration from environment variables (never hardcode credentials)
    rabbitmq_host = os.environ.get("RABBITMQ_HOST", "localhost")
    rabbitmq_port = int(os.environ.get("RABBITMQ_PORT", "15672"))
    admin_user = os.environ.get("RABBITMQ_ADMIN_USER")
    admin_password = os.environ.get("RABBITMQ_ADMIN_PASSWORD")
    use_ssl = os.environ.get("RABBITMQ_USE_SSL", "true").lower() == "true"

    if not admin_user or not admin_password:
        print("ERROR: RABBITMQ_ADMIN_USER and RABBITMQ_ADMIN_PASSWORD environment variables must be set.")
        print("Example:")
        print("  export RABBITMQ_ADMIN_USER=admin")
        print("  export RABBITMQ_ADMIN_PASSWORD='your-secure-password'")
        return

    scheme = "https" if use_ssl else "http"

    manager = RabbitMQManager(
        host=rabbitmq_host,
        port=rabbitmq_port,
        admin_user=admin_user,
        admin_password=admin_password,
        scheme=scheme,
        verify_ssl=use_ssl
    )

    # Define tenants with their specific queue configurations
    tenants = {
        "ecommerce": {
            "queues": ["orders", "payments", "notifications"],
            "max_queues": 50,
            "max_connections": 20
        },
        "analytics": {
            "queues": ["events", "metrics", "reports"],
            "max_queues": 100,
            "max_connections": 30
        },
        "messaging": {
            "queues": ["chat", "email", "sms"],
            "max_queues": 75,
            "max_connections": 25
        }
    }

    # Store tenant configurations securely
    tenant_configs = {}

    # Set up each tenant
    for tenant_name, config in tenants.items():
        result = manager.setup_tenant(
            tenant_name=tenant_name,
            app_queues=config["queues"],
            max_queues=config["max_queues"],
            max_connections=config["max_connections"]
        )
        if result:
            tenant_configs[tenant_name] = result

    # List all vhosts
    print("\nAll Virtual Hosts:")
    print("-" * 40)
    vhosts = manager.list_vhosts()
    for vhost in vhosts:
        print(f"  - {vhost.get('name', 'N/A')}: {vhost.get('description', '')}")

    # List all users
    print("\nAll Users:")
    print("-" * 40)
    users = manager.list_users()
    for user in users:
        print(f"  - {user.get('name', 'N/A')} (tags: {user.get('tags', '')})")

    # Run isolation audit
    issues = manager.audit_vhost_isolation()

    # Print summary
    print("\n" + "=" * 60)
    print("TENANT CONFIGURATION SUMMARY")
    print("=" * 60)
    for tenant_name, config in tenant_configs.items():
        print(f"\nTenant: {tenant_name}")
        print(f"  Vhost: {config['vhost']}")
        print(f"  Username: {config['username']}")
        print(f"  Password: {'*' * 8} (stored securely)")
        print(f"  Queue Pattern: {config['queue_pattern']}")

    if issues:
        print(f"\n⚠ {len(issues)} isolation issue(s) found. Please review the audit report above.")
    else:
        print("\n✓ All vhost isolation checks passed.")


if __name__ == "__main__":
    main()